export function getAllFlashcards(): Flashcard[] {
  return flashcards;
}

export function getCategories(): Category[] {
  const categories = [...new Set(flashcards.map((f) => f.category))];
  return categories;
}

export function getFlashcardsByCategory(category: Category): Flashcard[] {
  return flashcards.filter((f) => f.category === category);
}
